const call = $json.call;
const custom = call.call_analysis?.custom_analysis_data ?? {};

const patientName = custom.patientName ?? 'Patient';
const patientPhone = call.from_number ?? custom.patientPhone ?? null;
const patientEmail = custom.patientEmail ?? null;
const appointmentDate = custom.appointmentDate ?? null;
const appointmentTime = custom.appointmentTime ?? null;
const clinicianName = custom.clinicianName ?? 'our physiotherapist';
const appointmentType = custom.appointmentType === 'follow_up' ? 'follow-up appointment' : 'initial assessment';

// SMS body
const smsBody = `Hi ${patientName}, this is a confirmation from Spires Physiotherapy. Your ${appointmentType} with ${clinicianName} is confirmed${appointmentDate ? ` for ${appointmentDate}` : ''}${appointmentTime ? ` at ${appointmentTime}` : ''}. Reply CANCEL to cancel (24h notice required). See you soon.`;

// Email body (plain text)
const emailBody = `Hi ${patientName},\n\nGreat news — your ${appointmentType} at Spires Physiotherapy has been confirmed.\n\n${appointmentDate ? `Date: ${appointmentDate}` : ''}\n${appointmentTime ? `Time: ${appointmentTime}` : ''}\nClinician: ${clinicianName}\n\nWhat to bring:\n- Comfortable clothing that allows access to the area being treated\n- Any relevant scans, X-rays, or letters from your GP\n\nAddress: Compayne Gardens, West Hampstead, London NW6 3DD\nNearest station: West Hampstead (Jubilee/Thameslink/Overground — 5 min walk)\n\nIf you need to cancel or rebook, please give us 24 hours' notice. You can call us on 020 7794 0202 and Ava will help.\n\nSee you soon,\nThe Spires Physiotherapy team`;

return [{
  patientName,
  patientPhone,
  patientEmail,
  smsBody,
  emailBody,
  emailSubject: `Appointment confirmed — Spires Physiotherapy${appointmentDate ? `, ${appointmentDate}` : ''}`,
  callId: call.call_id,
  hasPhone: !!patientPhone,
  hasEmail: !!patientEmail,
}];
